import { Module } from "@medusajs/framework/utils"

import MessagingFiltersModuleService from "./service"

export const MESSAGING_FILTERS_MODULE = "messagingFilters"

export * from "./types/common"
export { MessagingFiltersModuleService }

export default Module(MESSAGING_FILTERS_MODULE, {
  service: MessagingFiltersModuleService,
})

import { MedusaService } from "@medusajs/framework/utils"

import { FilterRule } from "./models/filter-rule"
import { BlockedMessageLog } from "./models/blocked-message-log"
import {
  CompiledRuleset,
  FilterEvaluationResult,
} from "./types/common"

class MessagingFiltersModuleService extends MedusaService({
  FilterRule,
  BlockedMessageLog,
}) {
  evaluateMessage(
    body: string,
    ruleset: CompiledRuleset
  ): FilterEvaluationResult {
    const lowercasedBody = body.toLowerCase()
    const words = lowercasedBody.split(/\s+/)

    // 1. Exact word match — O(1) per word via hash set
    for (const word of words) {
      if (ruleset.exactWords.has(word)) {
        const ruleId = ruleset.exactRules.get(word)
        return {
          matched: true,
          rule_id: ruleId,
          match_type: "exact",
          pattern: word,
        }
      }
    }

    // 2. Contains/substring match — O(n) per pattern
    for (const entry of ruleset.containsPatterns) {
      if (lowercasedBody.includes(entry.pattern)) {
        return {
          matched: true,
          rule_id: entry.id,
          match_type: "contains",
          pattern: entry.pattern,
        }
      }
    }

    // 3. Regex match (built-in only) — O(n) per pattern
    for (const entry of ruleset.regexPatterns) {
      if (entry.regex.test(body)) {
        return {
          matched: true,
          rule_id: entry.id,
          match_type: "regex",
          pattern: entry.regex.source,
        }
      }
    }

    return { matched: false }
  }
}

export default MessagingFiltersModuleService

export type MatchType = "exact" | "contains" | "regex"

export interface FilterRuleDTO {
  id: string
  match_type: MatchType
  pattern: string
  is_builtin: boolean
  is_enabled: boolean
  description: string | null
  created_at: Date | string
  updated_at: Date | string
  deleted_at: Date | string | null
}

export interface BlockedMessageLogDTO {
  id: string
  sender_id: string
  sender_type: "customer" | "seller"
  conversation_id: string
  matched_rule_id: string
  message_body: string
  created_at: Date | string
  updated_at: Date | string
  deleted_at: Date | string | null
}

export interface CompiledRuleset {
  exactWords: Set<string>
  exactRules: Map<string, string> // lowercased word -> rule id
  containsPatterns: Array<{ id: string; pattern: string }> // lowercased
  regexPatterns: Array<{ id: string; regex: RegExp }>
}

export interface FilterEvaluationResult {
  matched: boolean
  rule_id?: string
  match_type?: MatchType
  pattern?: string
}

export interface AdminFilterRuleResponse {
  filter: FilterRuleDTO
}

export type AdminFilterRuleListResponse = {
  filters: FilterRuleDTO[]
