type ConversationListResponse = {
  conversations: ConversationDTO[]
  next_cursor: string | null
}

type ConversationDetailResponse = {
  conversation: ConversationDTO
  messages: MessageDTO[]
  next_cursor: string | null
  buyer_orders: any[]
}

type UnreadResponse = {
  unread_count: number
}

export const useVendorConversations = (
  query?: { cursor?: string; limit?: number },
  options?: Omit<
    UseQueryOptions<ConversationListResponse, ClientError>,
    "queryKey" | "queryFn"
  >
) => {
  const { data, ...rest } = useQuery({
    queryKey: conversationsQueryKeys.list(query),
    queryFn: async () =>
      (client as any).vendor.messages.query(query ?? {}) as Promise<ConversationListResponse>,
    ...options,
  })

  return { ...data, ...rest }
}

export const useVendorConversation = (
  id: string,
  query?: { limit?: number },
) => {
  const limit = query?.limit ?? 20

  const { data, fetchNextPage, hasNextPage, isFetchingNextPage, ...rest } =
    useInfiniteQuery<ConversationDetailResponse, ClientError>({
      queryKey: conversationsQueryKeys.detail(id, { limit }),
      queryFn: async ({ pageParam }) =>
        (client as any).vendor.messages.$id.query({
          $id: id,
          limit,
          ...(pageParam ? { cursor: pageParam } : {}),
        }) as Promise<ConversationDetailResponse>,
      initialPageParam: undefined as string | undefined,
      getNextPageParam: (lastPage) => lastPage.next_cursor ?? undefined,
    })

  const conversation = data?.pages[0]?.conversation
  const buyer_orders = data?.pages[0]?.buyer_orders
  const messages = data?.pages.flatMap((p) => p.messages) ?? []

  return {
    conversation,
    messages,
    buyer_orders,
    fetchNextPage,
    hasNextPage,
    isFetchingNextPage,
    ...rest,
  }
}

export const useVendorUnread = (
  options?: Omit<
    UseQueryOptions<UnreadResponse, ClientError>,
    "queryKey" | "queryFn"
  >
) => {
  const { data, ...rest } = useQuery({
    queryKey: unreadQueryKeys.detail("total"),
    queryFn: async () =>
      (client as any).vendor.messages.unread.query() as Promise<UnreadResponse>,
    ...options,
  })

  return { ...data, ...rest }
}

export const useSendVendorReply = (
  conversationId: string,
  options?: UseMutationOptions<{ message: MessageDTO }, ClientError, { body: string }>
) => {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: (payload: { body: string }) =>
      (client as any).vendor.messages.$id.mutate({ $id: conversationId, ...payload }) as Promise<{ message: MessageDTO }>,
    onSuccess: (data, variables, context) => {
      queryClient.invalidateQueries({
        queryKey: conversationsQueryKeys.detail(conversationId),
      })
      queryClient.invalidateQueries({
        queryKey: conversationsQueryKeys.lists(),
      })
      queryClient.invalidateQueries({
        queryKey: unreadQueryKeys.all,
      })
      options?.onSuccess?.(data, variables, context)
    },
    ...options,
  })
}

export const useMarkVendorRead = (
  conversationId: string,
  options?: UseMutationOptions<{ success: boolean }, ClientError, void>
) => {
  const queryClient = useQueryClient()

  return useMutation({
    mutationFn: () =>
      (client as any).vendor.messages.$id.read.mutate({ $id: conversationId }) as Promise<{ success: boolean }>,
    onSuccess: (data, variables, context) => {
      queryClient.invalidateQueries({
        queryKey: conversationsQueryKeys.detail(conversationId),
      })
      queryClient.invalidateQueries({
        queryKey: conversationsQueryKeys.lists(),
      })
      queryClient.invalidateQueries({
        queryKey: unreadQueryKeys.all,
      })
      options?.onSuccess?.(data, variables, context)
    },
    ...options,
  })
}

import { useEffect, useRef } from "react"
import { useQueryClient } from "@tanstack/react-query"
import { conversationsQueryKeys, unreadQueryKeys } from "./messaging"

declare const __BACKEND_URL__: string

type SSEStatus = "connecting" | "connected" | "disconnected" | "polling"

const POLLING_INTERVAL_LIST = 30000
const POLLING_INTERVAL_UNREAD = 15000

export const useMessagingSSE = (
  activeConversationId?: string,
  onStatusChange?: (status: SSEStatus) => void
) => {
  const queryClient = useQueryClient()
  const eventSourceRef = useRef<EventSource | null>(null)
  const pollingRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const unreadPollingRef = useRef<ReturnType<typeof setInterval> | null>(null)
  const reconnectTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)
  const statusRef = useRef<SSEStatus>("disconnected")
  const mountedRef = useRef(true)

  // Store callbacks in refs to avoid dependency chains
  const onStatusChangeRef = useRef(onStatusChange)
  onStatusChangeRef.current = onStatusChange

  const activeIdRef = useRef(activeConversationId)
  activeIdRef.current = activeConversationId

  useEffect(() => {
    mountedRef.current = true

    const setStatus = (status: SSEStatus) => {
      statusRef.current = status
      onStatusChangeRef.current?.(status)
    }

    const invalidateQueries = () => {
      queryClient.invalidateQueries({ queryKey: conversationsQueryKeys.all })
      queryClient.invalidateQueries({ queryKey: unreadQueryKeys.all })
    }

    const invalidateConversation = (conversationId: string) => {
      queryClient.invalidateQueries({
        queryKey: conversationsQueryKeys.detail(conversationId),
      })
    }

    const stopPolling = () => {
      if (pollingRef.current) {
        clearInterval(pollingRef.current)
        pollingRef.current = null
      }
      if (unreadPollingRef.current) {
        clearInterval(unreadPollingRef.current)
        unreadPollingRef.current = null
      }
    }

    const startPolling = () => {
      if (pollingRef.current) return
      setStatus("polling")

      pollingRef.current = setInterval(() => {
        invalidateQueries()
      }, POLLING_INTERVAL_LIST)

      unreadPollingRef.current = setInterval(() => {
        queryClient.invalidateQueries({ queryKey: unreadQueryKeys.all })
      }, POLLING_INTERVAL_UNREAD)
    }

    const connect = () => {
      if (!mountedRef.current) return

      if (eventSourceRef.current) {
        eventSourceRef.current.close()
      }

      setStatus("connecting")

      const baseUrl = typeof __BACKEND_URL__ !== "undefined" ? __BACKEND_URL__ : ""
      const url = `${baseUrl}/vendor/messages/events`

      const es = new EventSource(url, { withCredentials: true })
      eventSourceRef.current = es

      es.addEventListener("connected", () => {
        setStatus("connected")
        stopPolling()
      })

      es.addEventListener("new_message", (event: MessageEvent) => {
        invalidateQueries()
        try {
          const data = JSON.parse(event.data)
          if (data.conversation_id) {
            invalidateConversation(data.conversation_id)
          }
        } catch {
          // Broad invalidation already handled above
        }
      })

      es.addEventListener("messages_read", (event: MessageEvent) => {
        invalidateQueries()
        try {
          const data = JSON.parse(event.data)
          if (data.conversation_id) {
            invalidateConversation(data.conversation_id)
          }
        } catch {
          // Broad invalidation already handled above
        }
      })

      es.addEventListener("unread_count", () => {
        queryClient.invalidateQueries({ queryKey: unreadQueryKeys.all })
      })

      es.onerror = () => {
        es.close()
        eventSourceRef.current = null
        startPolling()

        // Schedule reconnect — track timer so cleanup can cancel it
        reconnectTimerRef.current = setTimeout(() => {
          reconnectTimerRef.current = null
          if (mountedRef.current && statusRef.current === "polling") {
            connect()
          }
        }, 5000)
      }
    }

    connect()

    return () => {
      mountedRef.current = false
      if (eventSourceRef.current) {
        eventSourceRef.current.close()
        eventSourceRef.current = null
      }
      stopPolling()
      if (reconnectTimerRef.current) {
        clearTimeout(reconnectTimerRef.current)
        reconnectTimerRef.current = null
      }
    }
  }, [queryClient]) // queryClient is stable — no re-render loop

  return { status: statusRef.current }
}

